namespace MvcApp.Controllers
{
    using MvcApp.Models;

    public class ProductsController : Controller
    {
        private readonly AppDbContext _db = new AppDbContext();

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }

        [HttpGet]
        public async Task<ActionResult> Details(int id)
        {
            var product = await _db.Products
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = await _db.ProductReviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedUtc)
                .ToListAsync();

            var viewModel = new ProductDetailsViewModel
            {
                Id = product.Id,
                Name = product.Name,
                Reviews = reviews.Select(r => new ProductReviewViewModel
                {
                    Id = r.Id,
                    AuthorName = r.AuthorName,
                    CreatedUtc = r.CreatedUtc,
                    ReviewHtml = SanitizeAndFormatReview(r.ReviewText)
                }).ToList()
            };

            return View(viewModel);
        }

        private static string SanitizeAndFormatReview(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = Regex.Replace(encoded, @"\[(b)\](.*?)\[/\1\]", "<strong>$2</strong>", RegexOptions.IgnoreCase | RegexOptions.Singleline);
            encoded = Regex.Replace(encoded, @"\[(i)\](.*?)\[/\1\]", "<em>$2</em>", RegexOptions.IgnoreCase | RegexOptions.Singleline);

            return encoded;
        }
    }
}

@model MvcApp.Models.ProductDetailsViewModel

@{
    ViewBag.Title = Model.Name;
}

<h2>@Model.Name</h2>

<h3>Reviews</h3>

@if (Model.Reviews != null && Model.Reviews.Count > 0)
{
    <div class="reviews">
        @foreach (var review in Model.Reviews)
        {
            <div class="review">
                <div class="review-meta">
                    <strong>@review.AuthorName</strong>
                    <span>@review.CreatedUtc.ToString("yyyy-MM-dd HH:mm")</span>
                </div>
                <div class="review-body">
                    @Html.Raw(review.ReviewHtml)
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No reviews yet.</p>
}